```cpp
// add+modify_eas_records.hpp
#pragma once

#include <filesystem>
#include <map>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>
#include <vector>

#include "eas_common.hpp"
using namespace sqlgen;
using namespace sqlgen::literals;

template<typename T>
void add_eas_records(const std::string& table_name,
                     const std::vector<T>& records) {
  // Connect to the database
  auto conn = sqlgen::sqlite::connect(db_path).value();

  // Create insert statement using table name and records
  auto insert_stmt = sqlgen::insert_into(table_name)(conn, records);

  // Execute the insert operation
  insert_stmt.value();
}

void delete_eas_records_by_id(const std::string& table_name,
                               const std::string& record_id) {
  // Connect to the database
  auto conn = sqlgen::sqlite::connect(db_path).value();

  // Create delete statement with where condition for primary key
  auto delete_stmt = sqlgen::delete_from(table_name) 
                   | sqlgen::where("id"_c == record_id);

  // Execute the delete operation
  delete_stmt(conn).value();
}

void modify_eas_records_by_id(const std::string& table_name,
                               const std::string& record_id,
                               const std::string& col_name,
                               const auto& new_value) {
  // Connect to the database
  auto conn = sqlgen::sqlite::connect(db_path).value();

  // Create update statement with set operation and where condition
  auto update_stmt = sqlgen::update(table_name) 
                   | sqlgen::set(col_name, new_value)
                   | sqlgen::where("id"_c == record_id);

  // Execute the update operation
  update_stmt(conn).value();
}
```

## Explanation:

1. **`add_eas_records`**:
   - Uses `sqlgen::sqlite::connect()` to establish a database connection
   - Uses `sqlgen::insert_into()` to create an insert statement with the table name
   - Chains the connection and records using the function call operator `()`
   - Executes the operation with `.value()`

2. **`delete_eas_records_by_id`**:
   - Uses `sqlgen::delete_from()` to create a delete statement
   - Uses the pipe operator `|` to chain `sqlgen::where()` condition
   - Uses `"id"_c` literal to reference the primary key column
   - Executes the operation with `.value()`

3. **`modify_eas_records_by_id`**:
   - Uses `sqlgen::update()` to create an update statement
   - Uses `sqlgen::set()` to specify the column update
   - Uses `sqlgen::where()` to filter by primary key
   - Chains operations using the pipe operator `|`
   - Executes the operation with `.value()`

The implementation follows sqlgen's fluent API pattern and properly handles the database operations as specified in the assessment objectives.

