```cpp
#pragma once

#include <ranges>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace query_daily_traffic_metrics {

struct PageVisit {
  sqlgen::PrimaryKey<int> visit_id;
  std::string url;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> visit_time;
};

struct DailyTraffic {
  std::string visit_date;
  int total_visits;
  int unique_pages;
};

struct DailyTrafficView {
  static constexpr const char* tablename = "DailyTrafficView";
  static constexpr bool is_view = true;
  std::string visit_date;
  int total_visits;
  int unique_pages;
};

/**
 * Function: Calculate daily traffic metrics from a log table.
 * 
 * @return List of daily traffic metrics
 */
std::vector<DailyTraffic> query_daily_traffic_metrics() {
  using namespace sqlgen::literals;

  // Connect to the database
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");

  // Build the query using sqlgen
  auto query = sqlgen::select_from<PageVisit>(
      sqlgen::strftime("%Y-%m-%d", &PageVisit::visit_time).as<"visit_date">,
      sqlgen::count().as<"total_visits">,
      sqlgen::count_distinct(&PageVisit::url).as<"unique_pages">)
    | sqlgen::group_by(sqlgen::strftime("%Y-%m-%d", &PageVisit::visit_time))
    | sqlgen::order_by(sqlgen::strftime("%Y-%m-%d", &PageVisit::visit_time));

  // Execute the query and convert to vector
  return query(conn).to<std::vector<DailyTraffic>>().value();
}

}  // namespace query_daily_traffic_metrics
```

## Explanation of Implementation:

1. **Database Connection**: Uses `sqlgen::sqlite::connect("test_db.sqlite")` to establish a connection to the SQLite database.

2. **Query Construction**: Uses `sqlgen::select_from<PageVisit>` to start building the query on the PageVisit table.

3. **Field Selection**:
   - `sqlgen::strftime("%Y-%m-%d", &PageVisit::visit_time).as<"visit_date">` extracts the date from the timestamp and aliases it
   - `sqlgen::count().as<"total_visits">` counts total visits
   - `sqlgen::count_distinct(&PageVisit::url).as<"unique_pages">` counts distinct URLs

4. **Grouping and Ordering**: Uses the pipe operator `|` to chain:
   - `sqlgen::group_by(sqlgen::strftime("%Y-%m-%d", &PageVisit::visit_time))` to group by the extracted date
   - `sqlgen::order_by(sqlgen::strftime("%Y-%m-%d", &PageVisit::visit_time))` to order by the extracted date

5. **Execution and Conversion**: Calls the query with the connection and uses `.to<std::vector<DailyTraffic>>().value()` to execute and convert the results to the desired format.

This implementation follows all the specified requirements and uses the sqlgen library functions as documented in the reference materials.

