            "is_deleted"_c.set(1),
            "deleted_at"_c.set(sqlgen::sqlite::CURRENT_TIMESTAMP)
        ) | sqlgen::where(sqlgen::in("doc_id"_c, ids));

        // Execute the update
        auto update_result = update_stmt(conn);
        if (!update_result) {
            // Rollback on failure
            rollback(conn);
            return false;
        }

        // Commit transaction
        auto commit_result = commit(conn);
        if (!commit_result) {
            // Rollback on commit failure
            rollback(conn);
            return false;
        }

        return true;

    } catch (...) {
        // Rollback on any exception
        rollback(conn);
        return false;
    }
}

