  | sqlgen::inner_join<Product, "p">("product_id"_t1 == "product_id"_t2)
  // 3. Group by product name
  | sqlgen::group_by("name"_t2);

  // 4. Create the view using sqlgen::create_as with IF NOT EXISTS
  auto create_view_stmt = sqlgen::create_as<SalesSummary>(query) | sqlgen::if_not_exists;

