 * Function: Create a view SalesSummary that aggregates sales by product.
 * 
 * @return true if view creation succeeds, false otherwise
 */
bool create_view_sales_summary() {
  using namespace sqlgen::literals;

  // 1. Build the SELECT query using sqlgen::select_from
  auto query = sqlgen::select_from<Sale>(
      "name"_t2 | sqlgen::as<"product_name">,
      sqlgen::sum("quantity"_t1) | sqlgen::as<"total_quantity">,
      sqlgen::sum("amount"_t1) | sqlgen::as<"total_revenue">
  )
  // 2. Join with Product table
  | sqlgen::inner_join<Product, "p">("product_id"_t1 == "product_id"_t2)
  // 3. Group by product name
  | sqlgen::group_by("name"_t2);

  // 4. Create the view using sqlgen::create_as with IF NOT EXISTS
  auto create_view_stmt = sqlgen::create_as<SalesSummary>(query) | sqlgen::if_not_exists;

  // 5. Connect to the database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return false;
  }
  auto conn = *conn_result;

  // 6. Execute the CREATE VIEW statement
  std::string sql = sqlgen::sqlite::to_sql(create_view_stmt);
  auto exec_result = conn.execute(sql);

  return exec_result;
}

