```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>

namespace analyze_social_network {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
  std::string email;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> join_date;
  std::string city;
};

struct Friendship {
  int user1_id;
  int user2_id;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> created_at;
};

struct FriendConnection {
  std::string user1_name;
  std::string user2_name;
  int mutual_friend_count;
};

std::vector<FriendConnection> analyze_social_network_impl(const std::vector<User>& users, const std::vector<Friendship>& friendships) {
  using namespace sqlgen::literals;

  // 1. Connect to SQLite database
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");

  // 2. Create tables using sqlgen::create_table
  (sqlgen::create_table<User> | sqlgen::if_not_exists)(conn);
  (sqlgen::create_table<Friendship> | sqlgen::if_not_exists)(conn);

  // 3. Insert data using sqlgen::insert
  sqlgen::insert(users)(conn);
  sqlgen::insert(friendships)(conn);

  // 4. Execute queries using sqlgen's fluent interface

  // Query 1: Mutual friends using self-join and subquery
  auto mutual_friends_query = sqlgen::read<std::vector<FriendConnection>>
    | sqlgen::inner_join<User, "u1">("user_id"_t1 == "user1_id"_t2)
    | sqlgen::inner_join<Friendship, "f1">("user_id"_t1 == "user_id1"_t2)
    | sqlgen::inner_join<Friendship, "f2">("user_id2"_t2 == "user_id1"_t3)
    | sqlgen::inner_join<User, "u2">("user_id2"_t3 == "user_id"_t4)
    | sqlgen::where("user_id"_t1 < "user_id"_t4)
    | sqlgen::group_by("user_id"_t1, "user_id"_t4)
    | sqlgen::having(sqlgen::count() > 0)
    | sqlgen::select(
        "username"_t1 | sqlgen::as<"user1_name">,
        "username"_t4 | sqlgen::as<"user2_name">,
        sqlgen::count() | sqlgen::as<"mutual_friend_count">
