  auto conn = conn_result.value();

  // 2. Create tables with foreign key constraints
  auto create_parent = sqlgen::create_table<Parent>;
  auto create_child = sqlgen::create_table<Child>;

  // Chain table creation operations
  auto result = conn
      .and_then(create_parent)
      .and_then(create_child);

  if (!result) {
    return false;
  }

  // 3. Insert parent and child records with same parent_id
  Parent parent{1, "Parent Record"};
  Child child{1, 1, "Child Record"};

  // Chain insert operations
  result = result.value()
      .and_then([&](const auto& conn) { return sqlgen::insert(parent)(conn); })
      .and_then([&](const auto& conn) { return sqlgen::insert(child)(conn); });

  if (!result) {
