Based on the reference materials and detailed specifications, here's the complete implementation of the `analyze_department_employees` function:

```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace analyze_department_employees {

struct Department {
  sqlgen::PrimaryKey<int> department_id;
  std::string department_name;
  std::string location;
};

struct Employee {
  sqlgen::PrimaryKey<int> employee_id;
  int department_id;
  std::string first_name;
  std::string last_name;
  double salary;
};

struct JoinResult {
  std::optional<std::string> department_name;
  std::optional<std::string> first_name;
  std::optional<std::string> last_name;
  std::optional<double> salary;
};

struct JoinAnalysis {
  std::vector<JoinResult> inner_join_results;
  std::vector<JoinResult> left_join_results;
  std::vector<JoinResult> right_join_results;
  std::vector<JoinResult> full_join_results;
};

/**
 * analyze_department_employees
 * Provides data-join analysis between Department and Employee input collections by
 * creating temporary SQL tables, inserting the provided rows, and executing a
 * variety of join queries to produce join-output samples.
 * Returns: JoinAnalysis.
 */
JoinAnalysis analyze_department_employees_impl(const std::vector<Department>& depts, const std::vector<Employee>& emps) {
  using namespace sqlgen::literals;

  // 1. Create SQLite database connection
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");

  // 2. Create tables with if_not_exists modifier
  auto create_dept = sqlgen::create_table<Department> | sqlgen::if_not_exists;
  auto create_emp = sqlgen::create_table<Employee> | sqlgen::if_not_exists;

  create_dept(conn);
  create_emp(conn);

  // 3. Insert data using sqlgen::insert
  sqlgen::insert(depts)(conn);
  sqlgen::insert(emps)(conn);

  // 4. Perform INNER JOIN
  auto inner_query = sqlgen::select_from<Department, "d">("department_name"_t1, "first_name"_t2, "last_name"_t2, "salary"_t2)
                   .inner_join<Employee, "e">("d.department_id"_t1 == "e.department_id"_t2)
                   .to<std::vector<JoinResult>>();

  auto inner_results = inner_query(conn);

  // 5. Perform LEFT JOIN
  auto left_query = sqlgen::select_from<Employee, "e">("first_name"_t2, "last_name"_t2, "salary"_t2)
                  .left_join<Department, "d">("e.department_id"_t2 == "d.department_id"_t1)
                  .to<std::vector<JoinResult>>();

  auto left_results = left_query(conn);

  // 6. Perform RIGHT JOIN
  auto right_query = sqlgen::select_from<Department, "d">("department_name"_t1)
                   .right_join<Employee, "e">("d.department_id"_t1 == "e.department_id"_t2)
                   .to<std::vector<JoinResult>>();

  auto right_results = right_query(conn);

  // 7. Perform FULL JOIN
  auto full_query = sqlgen::select_from<Department, "d">("department_name"_t1)
                   .full_join<Employee, "e">("d.department_id"_t1 == "e.department_id"_t2)
                   .to<std::vector<JoinResult>>();

  auto full_results = full_query(conn);

  // 8. Return comprehensive analysis
  JoinAnalysis analysis;
  analysis.inner_join_results = std::move(inner_results);
  analysis.left_join_results = std::move(left_results);
  analysis.right_join_results = std::move(right_results);
  analysis.full_join_results = std::move(full_results);

  return analysis;
}

}  // namespace analyze_department_employees
```

## Key Implementation Details:

1. **Database Connection**: Uses `sqlgen::sqlite::connect()` to establish connection to "test_db.sqlite"

2. **Table Creation**: Uses `sqlgen::create_table<T> | sqlgen::if_not_exists` pattern to create tables only if they don't exist

3. **Data Insertion**: Uses `sqlgen::insert()` function to insert the provided department and employee data

4. **Join Operations**:
   - **INNER JOIN**: Matches employees with their departments
   - **LEFT JOIN**: Includes all employees even without departments
   - **RIGHT JOIN**: Includes all departments even without employees  
   - **FULL JOIN**: Combines all records from both tables

5. **Column Selection**: Uses table aliases ("d" for Department, "e" for Employee) and literal operators (`_t1`, `_t2`) to specify columns

6. **Result Mapping**: Uses `to<std::vector<JoinResult>>()` to map query results to the custom `JoinResult` structure

7. **Comprehensive Analysis**: Returns all join results in a structured `JoinAnalysis` object containing vectors of join results

This implementation demonstrates proper usage of sqlgen's fluent API for database operations, including table creation, data insertion, and complex join operations with proper type mapping.

