#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>

namespace delete_with_complex_condition {

struct User {
  sqlgen::PrimaryKey<int> id;
  int age;
  std::string status;
};

/**
 * This function demonstrates deleting with complex conditions.
 * Returns: std::string.
 */
inline std::string delete_with_complex_condition() {
    using namespace sqlgen::literals;

    // Create individual conditions
    auto age_condition = "age"_c < 18;
    auto status_condition = "status"_c == "inactive";

    // Combine conditions using logical OR
    auto combined_condition = age_condition || status_condition;

    // Apply the condition to delete_from using where() and pipe operator
    auto delete_stmt = sqlgen::delete_from<User> | sqlgen::where(combined_condition);

    // Convert to SQL string
    return sqlgen::sqlite::to_sql(delete_stmt);
}

}  // namespace delete_with_complex_condition
```

## Explanation of Implementation:

1. **Struct Definition**: The `User` struct is defined with `id`, `age`, and `status` fields as specified.

2. **Literal Operator Usage**: Using `using namespace sqlgen::literals` allows us to use the `_c` suffix to create column references like `"age"_c` and `"status"_c`.

3. **Individual Conditions**: 
   - `"age"_c < 18` creates a condition for age less than 18
   - `"status"_c == "inactive"` creates a condition for status equal to "inactive"

4. **Logical OR Combination**: The `||` operator from `sqlgen::transpilation` namespace is used to combine the two conditions into a single complex condition.

5. **Delete Statement Construction**:
   - `sqlgen::delete_from<User>` creates the base DELETE FROM statement
   - The pipe operator `|` is used to apply the `where()` clause with the combined condition

6. **SQL Generation**: `sqlgen::sqlite::to_sql()` converts the constructed statement object into the final SQL string.

The generated SQL would be similar to:
```sql
DELETE FROM User WHERE (age < 18) OR (status = 'inactive')
```

